        if not ZIP_DIR.exists():
            ZIP_DIR.mkdir()

        with zipfile.ZipFile(DOWNLOAD_DIR / filename, 'r') as zip_ref:
            zip_ref.extractall(ZIP_DIR)

        filenames = [f for f in os.listdir(ZIP_DIR) if os.path.isfile(os.path.join(ZIP_DIR, f))]

