import pandas as pd
import random
import re
def task_func(csv_file, column_name='data', pattern='\d+[xX]', sample_size=None, seed=42):
    try:
        df = pd.read_csv(csv_file)
    except FileNotFoundError:
        return pd.DataFrame()                                            

    if column_name not in df.columns:
        return pd.DataFrame()                                             

    matches = df[df[column_name].astype(str).str.contains(pattern, na=False, regex=True)]

    if sample_size is None:
        return matches
    else:
        if len(matches) == 0:
            return pd.DataFrame()                                       

        random.seed(seed)
        num_matches = len(matches)
        if sample_size >= num_matches:
            return matches

        random_indices = random.sample(range(num_matches), sample_size)
        sampled_matches = matches.iloc[random_indices]
        return sampled_matches

