import platform
import time
def task_func(url):
    try:
        if platform.system() == "Windows":
            process = subprocess.Popen(['start', '', url], shell=True, creationflags=subprocess.CREATE_NEW_PROCESS_GROUP)
        elif platform.system() == "Darwin":
            process = subprocess.Popen(['open', url], start_new_session=True)
        elif platform.system() == "Linux":
            process = subprocess.Popen(['xdg-open', url], start_new_session=True)
        else:
            print(f"Unsupported operating system: {platform.system()}")
            return -1

        time.sleep(0.1)

        return process.poll() if process.poll() is not None else 0                                       
    except Exception as e:
        print(f"Error opening URL: {e}")
        return -1

